@@ -1,102 +0,0 @@
-name: Duplicate Issue Detection
-
-on:
-  issues:
-    types: [opened]
-
-permissions:
-  issues: write
-
-jobs:
-  detect-duplicates:
-    runs-on: ubuntu-latest
-    steps:
-      - name: Find potential duplicates
-        uses: actions/github-script@v7
-        with:
-          script: |
-            const newIssue = context.payload.issue;
-            const newTitle = newIssue.title.toLowerCase();
-            const newBody = (newIssue.body || '').toLowerCase();
-
-            // Fetch recent open issues (up to 100)
-            const { data: openIssues } = await github.rest.issues.listForRepo({
-              owner: context.repo.owner,
-              repo: context.repo.repo,
-              state: 'open',
-              per_page: 100,
-              sort: 'created',
-              direction: 'desc',
-            });
-
-            // Simple keyword overlap scoring
-            function extractKeywords(text) {
-              return text
-                .replace(/[^a-z0-9\s]/g, ' ')
-                .split(/\s+/)
-                .filter(w => w.length > 4)
-                .filter(w => !['this', 'that', 'with', 'from', 'have', 'been', 'will', 'when', 'what', 'which', 'there', 'their', 'about', 'would', 'could', 'should'].includes(w));
-            }
-
-            function similarity(a, b) {
-              const wordsA = new Set(extractKeywords(a));
-              const wordsB = new Set(extractKeywords(b));
-              if (wordsA.size === 0 || wordsB.size === 0) return 0;
-              const intersection = [...wordsA].filter(w => wordsB.has(w)).length;
-              return intersection / Math.min(wordsA.size, wordsB.size);
-            }
-
-            const newText = `${newTitle} ${newBody}`;
-            const candidates = [];
-
-            for (const issue of openIssues) {
-              if (issue.number === newIssue.number) continue;
-              const issueText = `${issue.title.toLowerCase()} ${(issue.body || '').toLowerCase()}`;
-              const score = similarity(newText, issueText);
-              if (score > 0.4) {
-                candidates.push({ issue, score });
-              }
-            }
-
-            if (candidates.length === 0) {
-              core.info('No potential duplicates found.');
-              return;
-            }
-
-            // Sort by score descending, take top 3
-            candidates.sort((a, b) => b.score - a.score);
-            const top = candidates.slice(0, 3);
-
-            const lines = top.map(({ issue, score }) =>
-              `- #${issue.number} — **${issue.title}** (${Math.round(score * 100)}% overlap)`
-            );
-
-            const comment = [
-              '### 🔍 Potential Duplicate Issues Detected',
-              '',
-              'This issue may be similar to existing open issues:',
-              '',
-              ...lines,
-              '',
-              'Please check these issues before proceeding. If this is indeed a duplicate, close this issue and add your information to the existing one.',
-              '',
-              '_This comment was generated automatically by the duplicate detection workflow._',
-            ].join('\n');
-
-            await github.rest.issues.createComment({
-              owner: context.repo.owner,
-              repo: context.repo.repo,
-              issue_number: newIssue.number,
-              body: comment,
-            });
-
-            await github.rest.issues.addLabels({
-              owner: context.repo.owner,
-              repo: context.repo.repo,
-              issue_number: newIssue.number,
-              labels: ['possible-duplicate'],
-            }).catch(() => {
-              // Label may not exist yet — silently skip
-            });
-
-            core.info(`Found ${top.length} potential duplicate(s) for issue #${newIssue.number}`);
